      return iData.variante_id === svId;
    });
    const mats = items.reduce((s, i) => {
      const iData = i.data || i;
      return s + (Number(iData.cantidad || 0) * Number(iData.precio_unitario || 0));
    }, 0);
    const labor = (Number(svData.jornadas_desarrollo_tecnico || 0) * RATE_DEV)
                + (Number(svData.jornadas_ensamblaje_taller || 0) * RATE_ASSEMBLY)
                + (Number(svData.jornadas_instalacion_obra || 0) * RATE_INSTALL);
    grandTotal += mats + labor;
  }
  const cotData = cotizacion.data || cotizacion;
  grandTotal += Number(cotData.costos_operativos || 0)
             + Number(cotData.imprevistos_instalacion || 0)
             - Number(cotData.descuento_comercial || 0)
             + Number(cotData.ajuste_arbitrario || 0);

  const year = new Date().getFullYear();
  const count = contratos.length + 1;
  const codigo = 'CT-' + year + '-' + String(count).padStart(3, '0');
  const defaultObjeto = mySpaces.map((s, i) => {
    const sData = s.data || s;
    return (i + 1) + '. ' + (sData.nombre_espacio || 'Espacio');
  }).join('\n');

  const contratoId = 'con_' + Date.now();
  contrato = await api.saveItem('contratos', {
    id: contratoId,
    data: {
      proyecto_id: cotizacion.id,
      codigo_contrato: codigo,
      fecha_contrato: new Date().toISOString().split('T')[0],
      contratante_domicilio: clientDomicilio,
      plazo_ejecucion_texto: '4 a 5',
      holgura_dias: 8,
      garantia_anios: Number(cotData.garantia_anios ?? 2),
      objeto_items: defaultObjeto,
      valor_total: grandTotal,
      estado: 'firmado'
    }
  });
} else {
  const cData = contrato.data || contrato;
  await api.saveItem('contratos', {
    id: contrato.id,
    data: { ...cData, estado: 'firmado' }
  });
}

const proyectos = await api.query('proyectos');
const proyecto = proyectos.find(p => p.id === cotizacion.id);
if (proyecto) {
  const pData = proyecto.data || proyecto;
  await api.saveItem('proyectos', {
    id: proyecto.id,
    data: { ...pData, estado: 'produccion' }
  });
}

const cId = contrato.id || contrato.data?.id;
const obligaciones = await api.query('obligaciones_pendientes');
const obligacionExistente = obligaciones.find(o => {
  const oData = o.data || o;
  return oData.contrato_id === cId;
});

if (!obligacionExistente) {
  const valorTotalFinal = Number(contrato.valor_total || contrato.data?.valor_total || 0);
  const abono1 = Math.round(valorTotalFinal * 0.50);
  const abono2 = Math.round(valorTotalFinal * 0.25);
  const abono3 = valorTotalFinal - abono1 - abono2;
  const cotData = cotizacion.data || cotizacion;
  const nomProyecto = cotData.nombre_proyecto || 'Proyecto';
  const clId = cotData.cliente_id || '';

  await api.saveItem('obligaciones_pendientes', {
    data: {
      descripcion: 'Anticipo 50% — ' + nomProyecto,
      tipo: 'por_cobrar',
      monto_total: abono1,
      monto_pagado: 0,
      fecha_vencimiento: new Date().toISOString().slice(0, 10),
      estado: 'pendiente',
      cliente_id: clId,
      proyecto_id: cotizacion.id,
      contrato_id: cId,
      descripcion_semantica: 'Primer cobro del 50% correspondiente al anticipo para iniciar la fabricación del proyecto ' + nomProyecto + '.'
    }
  });

  await api.saveItem('obligaciones_pendientes', {
    data: {
      descripcion: 'Instalación 25% — ' + nomProyecto,
      tipo: 'por_cobrar',
      monto_total: abono2,
      monto_pagado: 0,
      fecha_vencimiento: new Date().toISOString().slice(0, 10),
      estado: 'pendiente',
      cliente_id: clId,
      proyecto_id: cotizacion.id,
      contrato_id: cId,
      descripcion_semantica: 'Segundo cobro del 25% al iniciar la instalación física del mobiliario para el proyecto ' + nomProyecto + '.'
    }
  });

  await api.saveItem('obligaciones_pendientes', {
    data: {
      descripcion: 'Pago Final 25% — ' + nomProyecto,
      tipo: 'por_cobrar',
      monto_total: abono3,
      monto_pagado: 0,
      fecha_vencimiento: new Date().toISOString().slice(0, 10),
      estado: 'pendiente',
      cliente_id: clId,
      proyecto_id: cotizacion.id,
      contrato_id: cId,
      descripcion_semantica: 'Tercer y último cobro del 25% contra entrega a satisfacción del proyecto ' + nomProyecto + '.'
    }
  });
}

const existingOrders = await api.query('ordenes_trabajo');
const existing = existingOrders.find(o => {
  const oData = o.data || o;
  return oData.proyecto_id === cotizacion.id;
});
if (!existing) {
  const year = new Date().getFullYear();
  const count = existingOrders.length + 1;
  const codigo = 'OT-' + year + '-' + String(count).padStart(3, '0');
  const cotData = cotizacion.data || cotizacion;
  const dias = cotData.dias_entrega_estimados;
  let fechaEntrega = '';
  if (dias) {
    const d = new Date();
    d.setDate(d.getDate() + Number(dias));
    fechaEntrega = d.toISOString().split('T')[0];
  }
  await api.saveItem('ordenes_trabajo', {
    data: {
      proyecto_id: cotizacion.id,
      codigo_orden: codigo,
      estado: 'pendiente',
      fecha_entrega: fechaEntrega,
      notas: 'Creada automáticamente al enviar a producción.'
    }
  });
}

api.notify.success('Proyecto enviado a producción. Contrato y obligaciones de cobro (50%, 25%, 25%) creados axiomáticamente.');

