async function run({ payload, vault }) {
  const { proyecto_id } = payload;
  if (!proyecto_id) throw new Error("proyecto_id requerido");
  const espacios = (await vault.query("espacio_variantes")).filter(e => e.data.proyecto_id === proyecto_id);
  const espacioIds = espacios.map(e => e.id);
  const allItems = (await vault.query("items_variante")).filter(i => espacioIds.includes(i.data.variante_id) && !i.data.anulado && !i.data.compra_generada);
  if (!allItems.length) return { message: "No hay ítems pendientes de compra." };
  const catalogo = await vault.query("productos_catalogo");
  const catMap = Object.fromEntries(catalogo.map(c => [c.id, c.data]));
  const groups = {};
  const COMODIN = "__por_asignar__";
  for (const item of allItems) {
    const cat = catMap[item.data.catalogo_id] || {};
    const provId = cat.proveedor_id || COMODIN;
    if (!groups[provId]) groups[provId] = { items: [], total: 0 };
    const costo = (cat.precio_directo || cat.precio_publico || item.data.precio_unitario || 0);
    const linea = costo * (item.data.cantidad || 1);
    groups[provId].items.push(item);
    groups[provId].total += linea;
  }
  for (const [provId, group] of Object.entries(groups)) {
    await vault.write("compras_materiales", { descripcion: "OC Taller — Proy " + proyecto_id.slice(0,8), cantidad: group.items.length, costo_real_compra: group.total, proveedor_id: provId === COMODIN ? null : provId, fecha_compra: new Date().toISOString().slice(0,10), estado: "pendiente", origen_proyecto: proyecto_id });
    await vault.write("obligaciones_pendientes", { descripcion: "Compra materiales — Prov. " + (provId === COMODIN ? "Por Asignar" : provId.slice(0,8)), tipo: "por_pagar", monto_total: group.total, monto_pagado: 0, estado: "pendiente", proveedor_id: provId === COMODIN ? null : provId, proyecto_id: proyecto_id });
    for (const item of group.items) { await vault.write("items_variante", { ...item.data, compra_generada: true }, item.id); }
  }
  return { message: "Ordenes de compra generadas.", grupos: Object.keys(groups).length };
}

async function run({ payload, vault }) {
  const { usuario_id, tarea_id, horas, proyecto_id } = payload;
  if (!usuario_id || !horas) throw new Error("usuario_id y horas son requeridos");
  const usuarios = await vault.query("usuarios_equipo");
  const usuario = usuarios.find(u => u.id === usuario_id);
  const costoHora = usuario?.data?.costo_hora || 0;
  await vault.write("registro_horas", { fecha: new Date().toISOString().slice(0,10), usuario_id, proyecto_id: proyecto_id || null, horas_ordinarias: horas, horas_extras: 0, descripcion_semantica: "Registro desde tarea " + (tarea_id || "manual"), estado_pago: "pendiente" });
  return { message: "Horas registradas.", costo_total: costoHora * horas };
}

async function run({ payload, vault }) {
  const { proyecto_id } = payload;
  if (!proyecto_id) throw new Error("proyecto_id requerido");
  const compras = (await vault.query("compras_materiales")).filter(c => c.data.origen_proyecto === proyecto_id);
  const totalCompras = compras.reduce((sum, c) => sum + (c.data.costo_real_compra || 0), 0);
  const horas = (await vault.query("registro_horas")).filter(h => h.data.proyecto_id === proyecto_id);
  const usuarios = await vault.query("usuarios_equipo");
  const userMap = Object.fromEntries(usuarios.map(u => [u.id, u.data.costo_hora || 0]));
  const totalManoObra = horas.reduce((sum, h) => { const c = userMap[h.data.usuario_id] || 0; return sum + (c * (h.data.horas_ordinarias || 0)) + (c * 1.5 * (h.data.horas_extras || 0)); }, 0);
  const proyectos = await vault.query("proyectos");
  const proyecto = proyectos.find(p => p.id === proyecto_id);
  if (proyecto) { await vault.write("proyectos", { ...proyecto.data, costos_operativos: totalCompras + totalManoObra }, proyecto.id); }
  return { totalCompras, totalManoObra, costoTotal: totalCompras + totalManoObra };
}

async function run({ payload, vault }) {
  const { movimiento_id, obligacion_id } = payload;
  if (!movimiento_id || !obligacion_id) throw new Error("movimiento_id y obligacion_id requeridos");
  const mov = (await vault.query("movimientos_financieros")).find(m => m.id === movimiento_id);
  if (!mov) throw new Error("Movimiento no encontrado");
  const obl = (await vault.query("obligaciones_pendientes")).find(o => o.id === obligacion_id);
  if (!obl) throw new Error("Obligación no encontrada");
  const montoPagado = (obl.data.monto_pagado || 0) + Math.abs(mov.data.monto || 0);
  const nuevoEstado = montoPagado >= (obl.data.monto_total || 0) ? "pagado" : "parcial";
  await vault.write("obligaciones_pendientes", { ...obl.data, monto_pagado: montoPagado, estado: nuevoEstado }, obl.id);
  await vault.write("movimientos_financieros", { ...mov.data, estado: "conciliado", obligacion_id: obligacion_id }, mov.id);
  const ref = "CONC-" + new Date().toISOString().slice(0,10).replace(/-/g, "") + "-" + movimiento_id.slice(0,4);
  await vault.write("comprobantes_financieros", { numero_referencia: ref, tipo: "conciliacion", descripcion_semantica: "Conciliación: Mov " + movimiento_id.slice(0,8) + " <-> Obl " + obligacion_id.slice(0,8) });
  return { message: "Conciliación exitosa.", estado_obligacion: nuevoEstado };
}

