const payloadData = payload || {};
const leadId = crypto.randomUUID();

await api.saveItem('leads', {
  id: leadId,
  data: {
    nombre_completo: payloadData.nombre_completo || '',
    telefono_whatsapp: payloadData.telefono_whatsapp || '',
    email: payloadData.email || '',
    barrio_zona: payloadData.barrio_zona || '',
    tipo_espacio: payloadData.tipo_espacio || '',
    estado_proyecto: payloadData.estado_proyecto || '',
    mensaje: payloadData.mensaje || '',
    gclid: payloadData.gclid || '',
    utm_source: payloadData.utm_source || '',
    utm_medium: payloadData.utm_medium || '',
    utm_campaign: payloadData.utm_campaign || ''
  }
});

const mensajePrellenado =
  `Hola Veta Dorada, soy ${payloadData.nombre_completo || 'un cliente interesado'}. ` +
  `Necesito un ${payloadData.tipo_espacio || 'proyecto a medida'}. ` +
  `Actualmente ${payloadData.estado_proyecto || 'quiero recibir asesoría'}.\n`;

const url =
  `https://wa.me/${payloadData.whatsapp_destino || '573001234567'}?text=${encodeURIComponent(mensajePrellenado.trim())}`;

api.dispatchEvent('open_url', { url, target: '_blank' });
api.notify.success('Solicitud registrada, te redirigimos a WhatsApp');

const payloadData = payload || {};
const leadId = payloadData.record?.id || payloadData.id;
const score = Number(payloadData.score_conversion);

if (!leadId) {
  api.notify.error('Lead no encontrado');
  return;
}

if (!Number.isFinite(score) || score < 1 || score > 10) {
  api.notify.error('El score de conversión debe estar entre 1 y 10');
  return;
}

const leads = await api.query('leads');
const lead = leads.find((item) => item.id === leadId);

if (!lead) {
  api.notify.error('Lead no encontrado');
  return;
}

await api.saveItem('leads', {
  id: lead.id,
  data: {
    ...(lead.data || lead),
    score_conversion: score
  }
});

api.notify.success('Score de conversión actualizado');

const transicionesLegales = {
  activa: ['enviada', 'en_contrato', 'perdida'],
  enviada: ['en_contrato', 'activa', 'perdida'],
  en_contrato: ['pre_produccion', 'produccion', 'entregado', 'cancelada'],
  pre_produccion: ['produccion', 'en_contrato', 'cancelada'],
  produccion: ['entregado', 'pre_produccion', 'cancelada'],
  entregado: [],
  perdida: [],
  cancelada: [],
};

const correccionesManuales = new Set([
  'enviada=>activa',
  'pre_produccion=>en_contrato',
  'produccion=>pre_produccion',
]);

const estadoActual = String(payload?.estado_actual ?? payload?.estadoActual ?? '').trim();
const estadoDestino = String(payload?.estado_destino ?? payload?.estadoDestino ?? '').trim();

if (!estadoActual || !estadoDestino) {
  api.notify.error('Faltan estado_actual o estado_destino.');
  throw new Error('Faltan estado_actual o estado_destino.');
}

const claveManual = estadoActual + '=>' + estadoDestino;
const destinosPermitidos = transicionesLegales[estadoActual] ?? [];
const permitido = estadoActual === estadoDestino || destinosPermitidos.includes(estadoDestino) || correccionesManuales.has(claveManual);

if (!permitido) {
  api.notify.error('Transicion ilegal: ' + estadoActual + ' -> ' + estadoDestino);
  throw new Error('Transicion ilegal: ' + estadoActual + ' -> ' + estadoDestino);
}

return {
  permitido: true,
  estado_actual: estadoActual,
  estado_destino: estadoDestino,
  correccion_manual: correccionesManuales.has(claveManual),
  sin_cambio: estadoActual === estadoDestino,
};

/**
 * Zap: recalcular_precio_prefabricado
 * Calcula el precio de costo de los prefabricados basado en sus componentes
 * Payload: { prefabricado_id? } — si no hay id, procesa todos
 */

const prefabricadoId = payload.prefabricado_id;

const prefabricados = await api.query('prefabricados');
const prefabricadosItems = await api.query('prefabricados_items');
const productosCatalogo = await api.query('productos_catalogo');

// Determinar qué prefabricados procesar
const targetPrefabs = prefabricadoId
  ? prefabricados.filter(p => p.id === prefabricadoId)
  : prefabricados;

if (targetPrefabs.length === 0) {
  api.notify.error('No se encontraron prefabricados para procesar.');
  return;
}

let actualizados = 0;
let errores = 0;

for (const prefab of targetPrefabs) {
  try {
    // Obtener los items del prefabricado
    const items = prefabricadosItems.filter(pi => pi.prefabricado_id === prefab.id);

    // Calcular costo sumando cantidad × precio_directo
    let costCalculado = 0;
    for (const item of items) {
      const producto = productosCatalogo.find(p => p.id === item.catalogo_id);
      if (producto) {
        const cantidad = Number(item.cantidad || 0);
        const precioDirecto = Number(producto.precio_directo || 0);
        costCalculado += cantidad * precioDirecto;
      }
    }

    // Actualizar el prefabricado con el costo calculado
    const datosActualizar = {
      ...prefab,
      precio_costo_calculado: costCalculado
    };

    // Si es reutilizable en catálogo y tiene espejo, actualizar el espejo
    if (prefab.reutilizable_catalogo && prefab.catalogo_id) {
      const espejo = productosCatalogo.find(p => p.id === prefab.catalogo_id);
      if (espejo) {
        await api.saveItem('productos_catalogo', {
          id: espejo.id,
          data: {
            ...espejo,
            precio_directo: costCalculado
          }
        });
      }
    }

    // Guardar el prefabricado actualizado
    await api.saveItem('prefabricados', {
      id: prefab.id,
      data: datosActualizar
    });

    actualizados++;
  } catch (e) {
    errores++;
    console.error(`Error procesando prefabricado ${prefab.id}:`, e);
  }
}

if (errores === 0) {
  api.notify.success(`${actualizados} prefabricado(s) recalculado(s) exitosamente.`);
} else {
  api.notify.warning(`Se actualizaron ${actualizados} prefabricado(s), pero ocurrieron ${errores} error(es).`);
}

const { cliente_id } = payload;
if (!cliente_id) {
  api.notify.error("cliente_id requerido en payload");
  return;
}

const proyectosRaw = await api.query("proyectos");
const clienteProyectos = proyectosRaw.filter((p) => p.cliente_id === cliente_id);

const proyectosSeguro = clienteProyectos.map((p) => ({
  id: p.id,
  nombre_proyecto: p.nombre_proyecto,
  estado: p.estado,
  dias_entrega_estimados: p.dias_entrega_estimados,
  barrio: p.barrio,
}));

api.dispatchEvent("portal_data", {
  proyectos: proyectosSeguro,
  total: proyectosSeguro.length,
});
